    $failures     = [int]$suiteNode.failures
    $skipped      = [int]$suiteNode.skipped
    $passed       = $tests_count - $failures - $skipped

    return [PSCustomObject]@{
        SourceFile = $Path
        Suite      = $suiteNode.name
        Passed     = $passed
        Failed     = $failures
        Skipped    = $skipped
        Duration   = [double]$suiteNode.time
        Tests      = $tests
    }
}

# ---------------------------------------------------------------------------
