    }

    It "output contains exact total count 16" {
        $script:actOutput | Should -Match "AGGREGATOR_RESULT_TOTAL=16"
    }

    It "act-result.txt artifact was created" {
        Test-Path "$PSScriptRoot/act-result.txt" | Should -BeTrue
    }
}

